var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color>\\n개발 부지, 섹터 <color=#ffd34c>E7</color> F-23","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>\\n開発地、セクター<color=#ffd34c>E7</color>、F-23。","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color>\\nDevelopment Site, Sector <color=#ffd34c>E7</color> F-23","TWN":"管理局直轄市<color=#ffd34c>查雷德</color>\\n開發用地，區域<color=#ffd34c>E7</color> F-23"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가… 방금 침식체들을 날려버린 건가…?","JPN":"私が……今、侵食体をふっ飛ばした……？","ENG":"Did I just... send the C.O.s flying...?","TWN":"我……剛剛打飛了侵蝕體……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"너… 힘을 가진 인간… 아니다.","JPN":"オマエ……力ヲ持ッテイル人間……違ウ。","ENG":"You... not human... with power.","TWN":"你……不是……擁有力量的人類。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"침식체도… 아니다.","JPN":"侵食体デモ……ナイ。","ENG":"Not... C.O.","TWN":"不是……侵蝕體。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"어떻게… 한 거지?","JPN":"ドウ……ヤッタ？","ENG":"How... you do that?","TWN":"如何……做到的？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"글쎄?","JPN":"さあね？","ENG":"I don’t know...","TWN":"不知道？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"네가 나한테서 찾던 가능성이란 게 이런 거 아니었나?","JPN":"君が私から探していた可能性ってこんなもんじゃなかった？","ENG":"But isn't this part of the possibilities that you were trying to find from me?","TWN":"這就是你在我身上尋找的可能性？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"잡아라.","JPN":"捕マエロ。","ENG":"Get her.","TWN":"抓住。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨…!","JPN":"レアさん……！","ENG":"Leah...!","TWN":"蕾亞……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"크리스?","JPN":"クリス？","ENG":"Chris?","TWN":"克莉絲？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"오지 마! 여긴 위험해!","JPN":"来るな！　ここは危ない！","ENG":"Stop! It's dangerous here!","TWN":"別過來，這裡很危險！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그건 아는데요! 제 뒤쪽도 위험해서요!","JPN":"わかってますけど！　私の後ろも危ないんです！","ENG":"I know that! But what's behind me is also dangerous!","TWN":"我知道，但我後方也有危險！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"죄송해요! 죄송합니다!","JPN":"すみません！　ごめんなさい！","ENG":"I'm sorry! I'm sorry!","TWN":"對不起！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저게… 대체 몇 마리야?","JPN":"あれって……いったい何匹だ？","ENG":"How... many is that anyway?","TWN":"這到底是……多少隻？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으아아, 따라잡힌다아!","JPN":"うあぁ、追いつかれる！","ENG":"Uaaah...! They're catching up to me!","TWN":"啊啊啊，快被追上了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"쳇.","JPN":"ちっ。","ENG":"Tch.","TWN":"嘖。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"왜 아까처럼 안 되는 거지?","JPN":"何でさっきみたいにならないんだ？","ENG":"Why isn't it working like before?","TWN":"為什麼不能像剛才那樣？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"방금처럼 뭔가 힘을 쓰게 해달라고.","JPN":"さっきのように何か力を使わせてよ。","ENG":"Let me use my power like I did just now.","TWN":"快使出剛才那股力量啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭐라도 좋으니…!","JPN":"何でもいいから……！","ENG":"C'mon! Anything...!","TWN":"不管是什麼都行……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으으으…….","JPN":"ううぅ……","ENG":"Ngh...","TWN":"呃呃呃……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어라? 침식체들이…?","JPN":"あれ？　侵食体が……？","ENG":"Huh? The C.O.s...","TWN":"什麼，侵蝕體……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"다가오지 못하고 있잖아?","JPN":"近づけないでいる？","ENG":"They can't come near us?","TWN":"他們被阻止靠近了？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이 보호막. 레아 씨가 한 거예요?","JPN":"このバリア。レアさんがやったんですか？","ENG":"This barrier, did you do it, Leah?","TWN":"這個防護網是蕾亞弄的？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"…그런 것 같긴 한데.","JPN":"……そうみたいだけど。","ENG":"...I think so.","TWN":"……我想是的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이대로 둘러싸인 채로 있어봐야…","JPN":"このまま囲まれていても……","ENG":"But even if we're safe in here...","TWN":"但就這樣繼續被包圍……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…빠져나갈 방법이 없다는 게 문제네요.","JPN":"……逃げるすべがないのが問題ですね。","ENG":"It's a whole other problem finding a way out of this mess.","TWN":"……依然無路可逃。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"앗! 보호막에 균열이…!","JPN":"あっ！　バリアに亀裂が……！","ENG":"Huh?! The barrier's cracking...!","TWN":"啊！防護網裂開了……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"끝… 이다.","JPN":"終ワリ……ダ。","ENG":"It's... over.","TWN":"完了……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"망했다.","JPN":"どうしよう。","ENG":"We're doomed.","TWN":"完蛋了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"죄송해요. 보호막보다 쓸모없는 카운터라서.","JPN":"ごめんなさい。バリアより役に立たないカウンターで。","ENG":"I'm sorry that I'm a useless Counter that's worse than this barrier.","TWN":"對不起，我是一個比防護網還沒用的制裁者。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"자기 폄하는 늙고나서 손주손녀들한테 해, 중사.","JPN":"自分を卑下するのは、老いてから孫たちにしてね、軍曹。","ENG":"Save the self-loathing for your grandkids, Sergeant.","TWN":"自嘲的話還是等你老了講給孫子聽吧，中士。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"오늘이 마지막은 아닌 것 같으니까.","JPN":"今日が最後ではなさそうだから。","ENG":"Because today's not going to be the end of us.","TWN":"因為今天你死不了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네…?","JPN":"えっ……？","ENG":"Huh...?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"엉뚱한 곳에서 빛이 번쩍이길래 와봤더니 이런 곳에 침식체가 잔뜩 모여 있었네.","JPN":"光が見えて来てみたら、思ってもみないところに侵食体が群れているとはね。","ENG":"I saw a bright flash and came to see what it was, only to find a bunch of C.O.s.","TWN":"我看到這裡突然冒出了閃光，過來一看發現聚集著好多侵蝕體。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"지금 저 사람들. 곤경에 처한 것 같네요.","JPN":"あの人たち今、困っているようですね。","ENG":"Those two... I think they're in danger.","TWN":"他們似乎陷入麻煩了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"목적지는 아니지만, 발견한 이상 도와줄 수밖에 없겠네.","JPN":"目的地じゃないけど、見つけてしまったからには助けるしかねぇな。","ENG":"It's not our destination, but guess we'll have to help them since we saw them.","TWN":"雖然這裡不是我的目的地，但既然已經發現了就只好幫忙了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그렇지, 코치?","JPN":"だろう？　コーチ。","ENG":"Isn't that right, Coach?","TWN":"對吧，教練？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론일세.","JPN":"無論だ。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"뭐라도 구해보려고 여기까지 왔는데, 그게 사람 목숨이라면 마다할 이유는 없지.","JPN":"助けるためにここまで来たのだ。それが人の命ならば、躊躇する理由はない。","ENG":"We came here to save something. So there's no reason to turn down a chance to save people's lives.","TWN":"千里迢迢來到這裡，竟然有機會拯救人命為何要拒絕呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"조금만 기다리세요! 저희가 당장 구해드리겠습니다!","JPN":"もう少しだけ待ってください！　今、私たちが助けます！","ENG":"Just hold on! We'll get you out of there!","TWN":"堅持住，我們來救你了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"갑주의 무게가 가벼워지는구나.","JPN":"鎧の重さが軽くなっていく。","ENG":"The weight of my armor is lifting.","TWN":"盔甲變輕了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그만큼 이 세계에 타기리온의 영향이 커지고 있다는 의미일 터.","JPN":"それだけこの世界にタギリオンの影響力が大きくなっているということであろう。","ENG":"Which means that Thagirion's influence on this world is getting bigger.","TWN":"這表示塔基里翁在這個世界上的影響力越來越大。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"화근을 찾아내어… 뿌리뽑아야 한다.","JPN":"災いのもとを見つけ出し...…根絶せねばならない。","ENG":"I must find the cause, and... eradicate it.","TWN":"必須尋找禍根……連根拔除。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>로터스 대균열</color>\\n고심도 좌표 <color=#ffd34c>그림자 전당</color> 코핀-<color=#ffd34c>6</color>","JPN":"<color=#ffd34c>ロータスの大亀裂</color>\\n高深度座標<color=#ffd34c>影の殿堂</color>、コフィン-<color=#ffd34c>6</color>","ENG":"<color=#ffd34c>Lotus Grand Dimension Crevice</color>\\nHyperdepth Coordinates, <color=#ffd34c>Shadow Palace,</color> Coffin-<color=#ffd34c>6</color>","TWN":"<color=#ffd34c>洛德斯大峽谷</color>\\n高深度座標 <color=#ffd34c>暗影殿堂</color> 科芬-<color=#ffd34c>6</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이걸로… 봉인의 마지막 단계만 남았어요.","JPN":"これで……封印は最後の段階だけ残っています。","ENG":"With this... only the last step of the seal remains.","TWN":"接下來……只剩下封印的最後一個步驟了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금쯤 배우들도 무대의 중심에 다다르고 있겠죠.","JPN":"今頃は役者たちも舞台の中心に来ているでしょう。","ENG":"The actors should be gathering at the main stage about now.","TWN":"此時，演員們應該快走到舞台中央了吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>클리파 봉인 해제- 최종 절차. 승인 거부.</color>","JPN":"<color=#ffd34c>クリファ封印解除-最終手続き。承認を拒絶。</color>","ENG":"<color=#ffd34c>Qlipha Seal Deactivated - Final Procedure. Approval denied.</color>","TWN":"<color=#ffd34c>解除逆卡巴拉封印——最終程式。拒絕授權。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>에너지 신호 부적합 판정.</color>","JPN":"<color=#ffd34c>エネルギー信号、不適切判定。</color>","ENG":"<color=#ffd34c>Energy signal, incompatible.</color>","TWN":"<color=#ffd34c>能量訊號不符合要求。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마지막 봉인을 열기 위해 필요한 조건은… 역시 이것.","JPN":"最後の封印を解くために必要な条件は……やはり、これ。","ENG":"The last piece to removing the seal is... this.","TWN":"打開最後一個封印的條件……果然是這個。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"자신의 힘으로 열 수 없는 자물쇠를 걸어 두다니. 대적자도 아니면서 제법 철저하시네요.","JPN":"自分の力では開けられない鍵をかけておくとは。敵対者でもないくせに、なかなか徹底していますね。","ENG":"A lock that even he can't open himself. Rather thorough from someone who is not even an Antagonist.","TWN":"竟然上了連自己也打不開的鎖。又不是對敵者，做得還真是徹底。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 곧, 열쇠가 직접 제 발로 여기 나타나 마지막 봉인을 열고 대미를 장식하겠죠.","JPN":"でも、もうすぐ鍵が自らの足でここに現れ、最後の封印を解き終わりを迎えるでしょう。","ENG":"But soon, the key to the lock will enter voluntarily to build up the grand finale.","TWN":"但不久之後，鑰匙會自己走上門來，打開最後的封印，造就一個完美的結局。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>관리자 권한 인식. 경계 해제.</color>","JPN":"<color=#ffd34c>管理者権限を認識。警戒解除。</color>","ENG":"<color=#ffd34c>Administrator authorization detected. Deactivating alarms.</color>","TWN":"<color=#ffd34c>確認管理者權限，警戒將解除。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>보안 시스템의 경계 대상을 재조정합니다.</color>","JPN":"<color=#ffd34c>セキュリティーシステムの警戒対象を再調整します。</color>","ENG":"<color=#ffd34c>Readjusting the security system's targets.</color>","TWN":"<color=#ffd34c>重新調整安全系統的警戒目標。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리국에서 알립니다.</color>","JPN":"<color=#ffd34c>管理局からお知らせします。</color>","ENG":"<color=#ffd34c>This is the Administration.</color>","TWN":"<color=#ffd34c>管理局通知。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이것은 실제 상황입니다.</color>","JPN":"<color=#ffd34c>これは訓練ではありません。</color>","ENG":"<color=#ffd34c>This is not a drill.</color>","TWN":"<color=#ffd34c>這不是演習。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재 눈보라 현상을 동반한 고위 침식파가 전세계를 뒤덮고 있습니다.</color>","JPN":"<color=#ffd34c>現在、吹雪を伴う高位の侵食波が全世界を覆いつくしています。</color>","ENG":"<color=#ffd34c>The high-grade Corruption ray accompanied by the blizzard is currently covering the world.</color>","TWN":"<color=#ffd34c>目前，一股伴有暴風雪的高強度侵蝕波正在席捲全世界。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시민 여러분께서는 절대 눈보라에 노출되지 마시고, 안전한 실내장소로 대피하여 재난방송을 청취해주시기 바랍니다.</color>","JPN":"<color=#ffd34c>市民の皆様は決して吹雪の中に出ず、室内の安全な場所に退避し、テレビ・ラジオをつけてください。</color>","ENG":"<color=#ffd34c>Citizens are asked to not be exposed to the snow, evacuate to a safe place indoors, and listen to the disaster broadcast.</color>","TWN":"<color=#ffd34c>各位市民千萬不要暴露在暴風雪中，請在室內躲避並收聽災害廣播。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안내된 지침은 재난경보 해제까지 유효합니다.</color>","JPN":"<color=#ffd34c>ご案内している行動指針は災難警報が解除されるまで有効です。</color>","ENG":"<color=#ffd34c>The broadcast guidelines will remain in effect until the disaster alert is lifted.</color>","TWN":"<color=#ffd34c>持續到警報解除為止。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 관리국이 해당 현상의 원인을 파악하고 해결 중에 있습니다.</color>","JPN":"<color=#ffd34c>現在、管理局ではこの現象の原因を把握し、解決に向けて動いています。</color>","ENG":"<color=#ffd34c>Currently, the Administration is finding the cause of this phenomenon and working to resolve it.</color>","TWN":"<color=#ffd34c>管理局目前正在努力找出原因要解決這個問題。</color>"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그러니 시민 여러분께선 관리국의 지침에 따라주시길 당부드립니다. </color>","JPN":"<color=#ffd34c>ですので、市民の皆様には管理局の行動指針に従ってくださいますようお願いいたします。</color>","ENG":"<color=#ffd34c>We ask that citizens follow the Administration's guidelines.</color>","TWN":"<color=#ffd34c>請各位市民務必遵循管理局的指示。</color>"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_19"},{"id":"L23_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"무슨 짓이지, 침식체! 누가 허락도 없이 함부로 여길 들어오라고 했나!","JPN":"何をしているのだ、侵食体！　許可なしでここに入っていいとは言ってないぞ！","ENG":"C.O.! What are you doing?! Who told you could come in here without permission?!","TWN":"你在幹什麼，侵蝕體！誰允許你擅自闖進這裡的！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"분명히 말했을 텐데? 주제를 잘 파악하라고!","JPN":"確かに言ったはずだが？　身の程をわきまえろ！","ENG":"Have I not made it clear? Know your place!","TWN":"我肯定已經說過了吧？搞清楚自己的位置！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"알고 있다. 죽기전에. 동포. 전해주었다.","JPN":"ワカッテイル。死ヌ前。仲間。伝エテクレタ。","ENG":"I know. Before dying. My kind. Delivered.","TWN":"我知道。在死之前。同胞。傳達了。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"처세술.","JPN":"世渡リ。","ENG":"Worldly wisdom.","TWN":"處世之道。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"죽기전에? 동포? 무슨 헛소리지?","JPN":"死ぬ前？　仲間？　どういうことだ？","ENG":"Before dying? Your kind? What nonsense is that?","TWN":"死之前？同胞？你在胡說什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"아무튼 알아들었으면, 당장 실험실로 돌아가!","JPN":"とにかくわかったなら今すぐ実験室に戻れ！","ENG":"If you heard me, go back to the lab this instant!","TWN":"總之，聽明白了就立刻回實驗室去！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"내 말 안 들리나! 침식체!","JPN":"聞こえないのか！　侵食体！","ENG":"Didn't you hear me?! C.O.!","TWN":"沒聽到我說話嗎！侵蝕體！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"사회 혼란. 들키지 않는다.","JPN":"社会混乱。バレナイ。","ENG":"Society confused. Not caught.","TWN":"社會混亂。不會。被發現。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"시체 발견되지 않으면. 들키지 않는다.","JPN":"死体、見ツカラナイ。バレナイ。","ENG":"The body is not found. Won't get caught.","TWN":"沒有屍體。不會。被發現。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"가능성 수확하고. 모방하면. 들키지 않는다.","JPN":"可能性ヲ収穫。模倣スル。バレナイ。","ENG":"Collect possibilities. And imitate. Won't get caught.","TWN":"收穫可能性。並模仿。不會。被發現。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"그 여자처럼…….","JPN":"アノ女ノヨウニ……","ENG":"Like that girl...","TWN":"就像那個女人……"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"모두 전해 받았다. 동포여.","JPN":"全テ伝ワッタ。仲間。","ENG":"I received all. My kind.","TWN":"都收到了。同伴們。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"큭, 큭큭……!! 큭큭큭!!","JPN":"クッ、ククッ……！！　クククッ！！","ENG":"Ke, keke...! KEKEKE!!","TWN":"咳咳……！！咳咳咳咳！！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"뭐라고 떠드는 거야! 이 망할 침식체가……!!","JPN":"何を言ってるんだ！　このくそ侵食体が……！！","ENG":"What are you saying?! You damned C.O....!","TWN":"在嚷嚷什麼呢！該死的侵蝕體……！！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"알고 있겠지? 이 버튼 한 번이면, 네놈은 핵이 파괴되어 소멸한다!","JPN":"わかってるだろう？　このボタンを押したら、貴様はコアが破壊されて消滅する！","ENG":"Do I have to remind you? With a press of a button, I can destroy your core!","TWN":"你應該知道吧？只要按下這個按鈕，你的核心就會被摧毀，徹底消失！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"그러니까 당장 실험실로……!","JPN":"だから今すぐ実験室に……！","ENG":"Now go back to the lab–","TWN":"所以立刻！馬上……！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"크하아악!! 내 팔이……!! 팔이……!!","JPN":"うわああっ！！　腕が……！！　腕が……！！","ENG":"AAARGH!! My arm...!! My arm...!!","TWN":"啊啊啊啊！！我的手……！！手臂……！！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"처세술.","JPN":"世渡リ。","ENG":"Worldly wisdom.","TWN":"處世之道。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"자신 보다 강한 사람한테 하는 것.","JPN":"自分ヨリ強イ人間ニスルモノ。","ENG":"Only for those stronger than you.","TWN":"只為。比自己強的人做事。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"이런 개자식이……!! 노예 주제에 감히 주인에게 반기를 들어……!?","JPN":"クソが……！！　奴隷のくせによくも主人に歯向かうのか……！！","ENG":"You bastard...! How dare a slave rebel against his master...?!","TWN":"混帳侵蝕體……！！你這奴隸竟敢反抗主人……！?"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"뒈져버려, 이 침식체……!!","JPN":"死ね、この侵食体……！！","ENG":"Die, C.O...!!","TWN":"去死吧，混蛋……！！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"이, 이게 대체 어떻게 된 거지……!? 어째서 버튼이……!?","JPN":"こ、これはどういうことだ……！？　どうしてボタンが……！？","ENG":"W-what's going on...?! Why won't the button work...?!","TWN":"這、這到底是怎麼回事……！？為什麼按鈕會……！?"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"서, 설마 합의체 녀석들……? 처음부터……?","JPN":"ま、まさか合意体のやつら……？　最初から……？","ENG":"D-did the Northern Union... From the start...?","TWN":"難、難道是和議會的那幫傢伙……？從一開始就……？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"약하다. 너.","JPN":"弱イ。オマエ。","ENG":"You. Weak.","TWN":"你。弱。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"자, 자, 자, 잠깐……!!","JPN":"ま、ま、ま、待て……！！","ENG":"W-w-w-wait...!!","TWN":"等、等、等、等等……！！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"협상, 협상이다, 침식체! 협상을 하는……!","JPN":"交渉、交渉だ、侵食体！　交渉しよう……！","ENG":"Y-yes, let's negotiate, C.O.! Negot–","TWN":"協商，協商吧，侵蝕體！我們來協商……！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"subtitle","speaker":null,"text":{"KOREA":"두 시간 뒤","JPN":"二時間後","ENG":"Two hours later","TWN":"兩小時後"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>로터스</color>\\n<color=#ffd34c>대균열 고심도</color> 그림자 전당","JPN":"管理局直轄都市<color=#ffd34c>ロータス</color>\\n<color=#ffd34c>大亀裂高深度</color>影の殿堂","ENG":"Administration Direct Control City, <color=#ffd34c>Lotus</color>\\n<color=#ffd34c>Grand Dimension Crevice Hyperdepths,</color> Shadow Palace","TWN":"管理局直轄市<color=#ffd34c>洛德斯</color>\\n<color=#ffd34c>大峽谷高深度</color>暗影殿堂"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"스완이란 사람, 혼자서 제법 대단한 일을 벌였네요.","JPN":"スワンという人、たった一人で凄いことをするんですね。","ENG":"This Swan person... She's done quite a lot on her own.","TWN":"這個叫史旺的傢伙，一個人做了這麼多不得了的事情。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"세상을 위험하게 만드는 봉인을 풀고, 우리가 올 걸 예상까지 하다니.","JPN":"世界を危険にさらす封印を解いて、私たちが来ることも予想するとは。","ENG":"She's removed the seal that puts the world in danger and predicted that we'll come.","TWN":"不僅打破了會使世界處於危險的封印，還預知了我們的到來。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"스완이 어떤 마술을 부렸는지는 저 방주 안으로 진입하면 알 수 있겠지.","JPN":"スワンがどんな仕業をしたのかはあの箱舟の中に侵入すればわかるだろう。","ENG":"I guess we'll see what kind of witchery she used after we infiltrate that Ark.","TWN":"等我們進入方舟，就會知道史旺到底施了什麼魔法。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 조심하게.","JPN":"だが、気を付けたまえ。","ENG":"Careful.","TWN":"但要小心。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"봉인이 대부분 해제된 방주의 내부는 이미 클리파 차원과 동화된 상태나 다름없을 테니까.","JPN":"封印がほぼ解かれた箱舟の中は既にクリファ次元と同化したような状態のはずだ。","ENG":"With the seal mostly removed, the inside of that Ark is likely to be synced with the Qlipha Dimension.","TWN":"方舟內部大部分封印已經解除，可能幾乎是與逆卡巴拉次元同化的狀態。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"클리파 차원이라니… 그게 대체 뭔가요?","JPN":"クリファ次元って……それはいったいなんですか？","ENG":"Qlipha Dimension...? What is that?","TWN":"逆卡巴拉次元…….那是什麼東西？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무너진 세계와 이어지는 통로.","JPN":"崩壊した世界に繋がる道。","ENG":"A tunnel linked to a destroyed world.","TWN":"與崩潰的世界連通的通道。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마왕의 강대한 힘을 현실로 끌어들일 만큼, 거대하면서도 불안정한…","JPN":"魔王の強力な力を現実に引き込むことができる、巨大ながらも不安定な……","ENG":"It has the power to bring the Demon Lord's potent powers into the Normalside. It's a massive, yet unstable...","TWN":"足以將魔王之力引入現實的強大又不穩定的……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가능성의 영역이지.","JPN":"可能性の領域だ。","ENG":"...area of possibilities.","TWN":"可能性之領域。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미나 양.","JPN":"ミナ君。","ENG":"Mina.","TWN":"米娜。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"만약 일이 잘못되어가고 있다고 느꼈을 땐, 날 믿고 하늘을 올려다보지 말게.","JPN":"もし何か間違っていると感じた時は、私を信じて空を見上げないようにしてくれ。","ENG":"If you feel that things are going wrong, trust me and don't look up into the sky.","TWN":"當你覺得事情不對勁，相信我，不要抬頭。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"두 사람도 미나 양 말이라면 따를 테니 말해두는 걸세.","JPN":"二人もミナ君の話なら従うはずだから、言っておく。","ENG":"I'm telling you since the other two will follow whatever you say.","TWN":"我和你說這些是因為另外兩個人都會聽從你的話。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…뭔진 모르겠지만 영 불안해지는 얘기네.","JPN":"……何のことかわからないけど、不安になる話だね。","ENG":"...I don't really get it, but it doesn't sound good.","TWN":"……雖然不知道是什麼，聽起來有些令人不安呢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그러니까 나한테만 말해둔다는 거지? 알겠어.","JPN":"だから、私にだけ言っておくということだね？　わかったよ。","ENG":"That's why I'm the only one you're telling, right? Okay.","TWN":"所以你只對我說了這些，對嗎？好吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이해해줘서 고맙네.","JPN":"理解してくれてありがとう。","ENG":"Thank you for understanding.","TWN":"謝謝理解。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼… 들어가자.","JPN":"じゃ……入ろう。","ENG":"Then... Let's go in.","TWN":"那麼……我們開始吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"어서 오게.","JPN":"ようこそ。","ENG":"Welcome.","TWN":"歡迎光臨。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"너무 늦지도, 이르지도 않게 등장해주었군.","JPN":"遅くも早くもない登場だな。","ENG":"You arrived just on time. It's not too late or too early.","TWN":"來得剛剛好。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 이걸로 함선의 시스템을 속인 건가?","JPN":"やはりこれで艦船のシステムを騙したのか？","ENG":"Is this how she fooled the ship's system?","TWN":"你就是這樣騙過艦船的安全系統的？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"시윤 군이 스완의 능력에 대해 경고해주긴 했지만…","JPN":"シリュウ君がスワンの能力について警告してくれたが……","ENG":"Shiyoon did give me a heads up about Swan's abilities, but...","TWN":"時雲警告過史旺的能力，但……"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"한번 본 것만으로 날 완벽하게 복제할 줄은 몰랐군.","JPN":"一度見ただけで私を完璧にコピーできるとは思わなかった。","ENG":"I would've never guessed she could clone me so perfectly after just seeing me once.","TWN":"沒想到只是看一眼就能完美複製我。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"스완이 가진 모방 능력은 겉모습만을 훔칠 뿐이지.","JPN":"スワンが持っている模倣能力は外見を真似るだけだな。","ENG":"Swan's imitation ability only steals one's appearance.","TWN":"史旺的模仿能力只限於外表。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"하지만 이 함선 내부는 이미 클리파에 잠식된 상태일세.","JPN":"しかしこの艦船の内部は既にクリファに侵食された状態。","ENG":"But the inside of this ship is already consumed by Qlipha.","TWN":"不過這艘艦船的內部已經被逆卡巴拉侵蝕了。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"클리파 차원 속에선 상상이 현실이 되기도 한다는 걸 자네도 알고 있잖나?","JPN":"クリファ次元の中では想像が現実になりうることを、君も知っているだろう？","ENG":"I'm sure you already know that within the Qlipha Dimension, imagination can become reality, right?","TWN":"你應該也知道，在逆卡巴拉次元裡任何想像都可以成為現實。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"그러니 난 그녀가 자네에 대해 아는 정보와 견해로 만들어진 복제품이라 할 수 있지.","JPN":"だから私は彼女が君について知っている情報と見解で作られたコピーと言える。","ENG":"So you can say that I'm a replica of you made from what she knows about you and her impression.","TWN":"所以可以說我是根據她對你的情報和見解製作而成的複製品。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"나 자신과 이야기하는 건… 확실히 어색한 경험이군.","JPN":"自分と話すのは……確かに気まずい経験だな。","ENG":"Talking to myself is... definitely an awkward experience.","TWN":"和自己對話……確實難以適應。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"관중으로 불러낸 날 굳이 자신과 마주하게 하는 이유가 뭐지?","JPN":"観客として呼んだ私にわざわざコピーを送りつけた理由はなんだ？","ENG":"Why would she assign me as her audience and make me talk to myself?","TWN":"為什麼要讓我這個觀眾面對自己？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"스완에겐 마지막 봉인의 열쇠가 <color=#ffd34c>그것</color>이라는 확신이 필요했거든.","JPN":"スワンには最後の封印の鍵が<color=#ffd34c>あれ</color>だという確信が必要だったんだ。","ENG":"That's because Swan needed to be sure that the key to the last seal was <color=#ffd34c>it</color>.","TWN":"史旺需要確定最後的封印鑰匙是<color=#ffd34c>那個東西</color>。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"이곳은 파노라마라 불리는 스완의 거울 아티팩트 속일세.","JPN":"ここはパノラマという、スワンの鏡のアーティファクトの中なのだ。","ENG":"This place is inside Swan's mirror Artifact called Panorama.","TWN":"這裡是全景，是史旺的鏡子人造神器內部。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"시간이 멈춘 이곳에선 거울이 투영한 나 자신을 꺾어야만 거울을 벗어날 수 있지.","JPN":"時間が止まったここでは鏡が映している自分自身に勝たなければ脱出できない。","ENG":"Time doesn't flow here, and the only way to escape is to defeat the reflection of yourself in the mirror.","TWN":"在這個時間靜止的地方，你只有打敗鏡子中的倒影才能逃離鏡子。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"지금 나보고 나 자신과 싸우라는 건가?","JPN":"私に自分自身と戦えと言っているのか？","ENG":"You want me to fight myself?","TWN":"你是讓我和我自己戰鬥？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"난 나 자신을 사랑하기 때문에 그렇게 할 수 없네.","JPN":"私は自分を愛しているから、そんなことはできない。","ENG":"I can't because I simply love myself too much.","TWN":"我做不到，因為我愛我自己。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"같은 힘을 가진 상대를 이기라니, 상식적으로 불가능한 일이군.","JPN":"同じ力を持っている相手に勝てとは、常識的に考えて不可能なことだな。","ENG":"Defeating an opponent of equal strength. That is undoubtedly impossible.","TWN":"從常理上講，我不可能擊敗擁有與我相同力量的對手。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"그렇게 할 수 없다면, 스완이 원하는 대답을 해야겠지.","JPN":"できないなら、スワンが望む答えを出さなければなるまい。","ENG":"If you can't, then you must give Swan the answer she wants.","TWN":"如果做不到，你就得給史旺她想要的答案。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"클리파 차원에 거울이 하나만 있을 거라고 생각말게.","JPN":"クリファ次元の中にある鏡が一つだけとは考えない方がいい。","ENG":"And don't think that there is only one mirror in the Qlipha Dimension.","TWN":"別以為逆卡巴拉次元裡只有一面鏡子。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"이미 수많은 나를 상대로 똑같은 질문을 하고 있을 테니 거짓말은 소용 없을 걸세.","JPN":"すでに多くの自分を相手に同じ質問をしているはずだから、嘘は何の意味もないだろう。","ENG":"Lying won't work, as I will be asking the same question across countless mirrors.","TWN":"她可能已經對無數個我提出了相同的問題，所以撒謊應該是沒用的。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"스완이 클리파 차원에서 일어나는 모든 가능성을 관측하고 있는 건가?","JPN":"スワンはクリファ次元で発生している全ての可能性を観察しているのか？","ENG":"Are you saying that Swan is observing all the possibilities that could happen within the Qlipha Dimension?","TWN":"你是說史旺在觀察逆卡巴拉次元中發生的所有可能性？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 이곳에서 무슨 대답을 하건, 스완은 원하는 답을 듣게 되겠군.","JPN":"ここで私が何を言っても、スワンは望む答えを聞けるってわけか。","ENG":"Then regardless of what I say here, Swan will get the answer she desires.","TWN":"不管我在這裡說什麼，史旺都會得到她想要的答案。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"마지막 봉인의 열쇠는 엘리시온의 위대한 정적이 가진 성흔의 에너지 패턴일세.","JPN":"最後の封印の鍵はエリシオンの偉大なる静寂が持っている聖痕エネルギーのパターンだ。","ENG":"The last key to the seal is the energy pattern of the Stigmata owned by the Great Silence of Elysion.","TWN":"最後一個封印鑰匙是艾利森偉大的寂靜擁有的聖痕能量模型。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"그렇다면 어째서 이미 그림자로 전락해버린 인간을 봉인의 열쇠로 선택한 거지?","JPN":"ならばどうして既にシャドウとなってしまった人間を封印の鍵として選択したんだ？","ENG":"Then, why did you choose a human who had already turned into a Shadow as the key to the seal?","TWN":"為什麼要選擇一個已經化為暗影的人類作為封印的鑰匙呢？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"훗날 완전해진 얼터니움으로 모르스를 되돌려 타기리온에게 대적하기 위함이었지.","JPN":"いつの日か完全になるオルタニウムでモールスを元に戻し、タギリオンと戦わせるためだった。","ENG":"It was to, one day, change back Mors with the completed Alternium so she could fight Thagirion.","TWN":"為了日後使用完整的黑化永恆之金找回死神，對抗塔基里翁。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"훗날 완전해진 얼터니움으로 모르스를 되돌려 타기리온에게 대적하기 위함이었지.","JPN":"いつの日か完全になるオルタニウムでモールスを元に戻し、タギリオンと戦わせるためだった。","ENG":"It was to, one day, change back Mors with the completed Alternium so she could fight Thagirion.","TWN":"為了日後使用完整的黑化永恆之金找回死神，對抗塔基里翁。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"훗날 완전해진 얼터니움으로 모르스를 되돌려 타기리온에게 대적하기 위함이었지.","JPN":"いつの日か完全になるオルタニウムでモールスを元に戻し、タギリオンと戦わせるためだった。","ENG":"It was to, one day, change back Mors with the completed Alternium so she could fight Thagirion.","TWN":"為了日後使用完整的黑化永恆之金找回死神，對抗塔基里翁。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"그래, 솔직하게 말해줘서 고맙네.","JPN":"そうか、素直に答えてくれてありがとう。","ENG":"All right. Thank you for your honesty.","TWN":"好吧，謝謝你坦誠回答。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"멈춘 시간에 갇혀 만 년이 넘도록 침묵하는 경우도 있었지만, 적어도 나의 세 가지 가능성은 같은 대답을 해줬군.","JPN":"止まった時間に閉じ込められて一万年以上沈黙しているときもあったが、少なくとも私の三つの可能性は同じ答えを出してくれた。","ENG":"There was a version of you that kept your silence for ten thousand years in frozen time. But at least my three possibilities gave me the same answer.","TWN":"也可能會被困在永恆的時間裡沉默千萬年，但至少我的三種可能性給出了相同的答案。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"사실 검증이 끝났으면 이 답답한 공간에서 날 좀 꺼내주겠나?","JPN":"事実の検証が済んだのならば、この窮屈な空間から出してくれないか？","ENG":"If you're done with fact-checking, could you let me out of this stuffy place?","TWN":"既然你已經驗證了事實，能不能請你讓我離開這個發悶的地方？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"원하는 답을 얻기 위해 사람을 만 년씩이나 가둬 두다니, 지독한 발상이군.","JPN":"望む答えを手にするために人を一万年も閉じ込めておくとは、酷いやり方だな。","ENG":"Trapping someone in there for ten thousand years just to get the answer you want. What a wicked idea.","TWN":"為了得到想要的答案而把人關上一萬年，真是個糟糕的主意。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"실례했어요.","JPN":"失礼しました。","ENG":"Pardon me.","TWN":"打擾了。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 그건 어차피 당신이 겪게 될 가능성 중 하나였을 뿐인 걸요.","JPN":"でもそれはあなたが経験するであろう可能性の一つに過ぎません。","ENG":"But that was merely one of the possibilities that you could have experienced.","TWN":"但無論如何，這只是你會遇到的可能性之一。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제아무리 당신이라도 실제로 그런 일을 겪었다면 미쳐버렸겠지만, 지금은 멀쩡하잖아요?","JPN":"さすがのあなたでも実際にそんな経験をしたら精神が崩壊してしまうかもしれませんが、今は平気でしょう？","ENG":"Even you would have gone insane if you had gone through that. But look at you now. You're just fine.","TWN":"如果發生在你身上，你一定會瘋掉吧。但你現在沒事不是嗎？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"클리파 차원을 이런 식으로 이용하는 건, 카운터가 아니라 마왕의 권능에 가까워보이는데.","JPN":"クリファ次元をこんな風に利用するのは、カウンターではなく魔王の権能に近いように見えるが。","ENG":"Manipulating the Qlipha Dimension like this seems closer to the powers of a Demon Lord than a Counter.","TWN":"以這種方式使用逆卡巴拉次元似乎更像是魔王的權能，而不是制裁者。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…맞아요. 타기리온과 계약해서 힘을 빌렸죠.","JPN":"……そうです。タギリオンと契約して力を借りました。","ENG":"...You're right. I made a deal with Thagirion to borrow her strength.","TWN":"……沒錯，我和塔基里翁簽訂了契約，借用了她的力量。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 목적을 달성하려면 그녀를 이곳에 끌어들여야 했으니까요.","JPN":"私の目的を達成するためには、彼女をここに誘い込む必要がありますから。","ENG":"I need her here in order to fulfill my objective.","TWN":"為了達成目的，我必須把她引到這裡。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이제 날 어떻게 할 셈이지?","JPN":"それで、私をどうするつもりだ？","ENG":"So what are you going to do with me now?","TWN":"你現在打算拿我怎麼辦？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"앞서 약속드렸다시피 관중으로서 예우해드릴 겁니다.","JPN":"先ほど約束したように観客として礼遇します。","ENG":"As promised, I'll treat you like the audience.","TWN":"正如我之前承諾的那樣，你將是這場演出的觀眾。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어차피 지금부터 당신은 다른 사람들을 지켜보는 것 말곤 아무것도 할 수 없을 테니까요.","JPN":"いずれにせよ今からあなたは他の人を見守ることしか、できることはないでしょう。","ENG":"But even then, all you will be able to do is watch the others from the sidelines.","TWN":"反正從現在開始，你什麼都做不了，只能靜靜看著別人。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"미나 양에게도 이런 방식이 위협이 될 거라고 생각하나?","JPN":"ミナ君にもこんな脅しが通じると思うのか？","ENG":"Do you think your threats will work on Mina too?","TWN":"你覺得這種威脅對米娜也行得通嗎？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"그들이 나처럼 순순히 당해주진 않을 걸세.","JPN":"彼らは私のようにおとなしくやられたりはしないだろう。","ENG":"They won't cave as easily as I did.","TWN":"她們可不會像我一樣會任你擺布。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"시도는 해보겠지만, 저도 그런 늑대가 그 정도 난관에 무너질 거란 기대는 하지 않아요.","JPN":"試してみますけど、私もあのオオカミがこの程度の試練に負けるとは思っていません。","ENG":"I'll try, but I, too, don't expect the Wolf to be discouraged by such an obstacle.","TWN":"我會嘗試，但我也知道她這種狼不會為這種程度的難關而倒下。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무력한 당신처럼 무한한 시간에 가둬 두고 괴롭힐 순 없겠죠.","JPN":"無力なあなたのように無限の時間に閉じ込め、いじめることもできませんし。","ENG":"Unlike the powerless you, I won't be able to torture her in infinite time.","TWN":"我沒辦法像對付弱小的你一樣把她困在永恆的時間裡。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 그건 상관없어요.","JPN":"でも、それは関係ありませんね。","ENG":"Nevertheless, it doesn't matter.","TWN":"但這並不重要。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어차피 제 목적은 그녀들을 굴복시키는 게 아니라 시간을 버는 것뿐이니까요.","JPN":"はなから私の目的は彼女たちを屈服させるのではなく、時間稼ぎですから。","ENG":"My goal isn't to make them surrender to me, but to buy time.","TWN":"我的目的只是爭取時間，而不是制伏她。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼 함께 감상해볼까요? 거울이 그녀들의 무엇을 비추는지.","JPN":"では一緒に見てみましょうか？　鏡が彼女たちの何を映し出すのか。","ENG":"Then, shall we watch together what the mirror will reflect for the girls?","TWN":"我們一起來看看她們的鏡子都照出了什麼。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"선배님…? 사장님…?! 다들 대체 어디 계세요오!","JPN":"先輩……？　社長……！？　みんなどこですかぁ！","ENG":"Mina...? Boss...?! Where is everyone?!","TWN":"前輩……？老闆……？！都跑哪去了？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"히잉, 어떻게 해야 여기서 나갈 수 있는 거지?","JPN":"ひいん、どうやったらここから出られるの？","ENG":"Hngh... How am I supposed to get out of here?","TWN":"唉，我該怎麼離開這裡？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"넌… 누구야? 왜 여기서 소리지르고 있어?","JPN":"あなたは……誰？　なんでここで叫んでるの？","ENG":"Who... who are you? Why are you screaming?","TWN":"你……你是誰？為什麼在這裡大喊大叫？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어라? 당신은…?","JPN":"あれ？　あなたは……？","ENG":"Huh? You...?","TWN":"唉？你……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저랑 똑같이 생겼잖아요?! 세상에 어떻게 이런 일이!!","JPN":"私とそっくりじゃないですか！？　どういうこと！！","ENG":"You look just like me! Oh my gosh!!","TWN":"你長得跟我一模一樣？！這到底是怎麼回事！！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_SERIOUS2"}}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"내가… 너처럼 생겼다고? 그게 정말이야?","JPN":"私が……あなたにそっくりですって？　それって本当なの？","ENG":"I... look like you? Really?","TWN":"我……我長得像你？真的？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우와, 뭐예요 그 이상한 반응은? 자기가 어떻게 생겼는지도 모른다고요?","JPN":"うわ、何ですかその反応。自分の顔もわからないのですか？","ENG":"Whoa, that's a weird reaction to have. Don't you know what you look like?","TWN":"哇，你反應怎麼這麼奇怪？難道連自己長什麼樣都不知道？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"몰랐어. 궁금해본 적 없으니까.","JPN":"知らなかった。気にしたこともないし。","ENG":"I didn't know. Because I've never really cared.","TWN":"我不知道，因為我從未想過。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아, 그러니까… 안녕하세요! 저는 노엘 라이트라고 해요!","JPN":"あ、ええと……こんにちは！　私はノエル・ライトといいます！","ENG":"Uh, well... Hi! I'm Noelle Wright!","TWN":"喔，那麼……嗨，我是洛艾兒·萊特！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아마, 당신의 이름도 노엘 라이트인 거죠?","JPN":"たぶん、あなたの名前もノエル・ライトなんですよね？","ENG":"I guess your name's also Noelle Wright?","TWN":"你應該也叫洛艾兒·萊特吧？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"이름…? 노엘 라이트…?","JPN":"名前……？　ノエル・ライト……？","ENG":"Name...? Noelle Wright...?","TWN":"名字……？洛艾兒·萊特……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"맞아. 그런 이름을 가졌으면 좋겠다고 생각한 적이 있어.","JPN":"そうだ。そんな名前が欲しいと思ったことはあったよ。","ENG":"Yeah. I thought it'd be nice to have a name like that.","TWN":"沒錯，我曾希望自己也有這樣的名字。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"너, 나랑 마음이 잘 맞는구나!","JPN":"あなた、私と気が合うのね！","ENG":"You and I are gonna be good friends!","TWN":"你和我的想法太一致了！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으음… 그러니까.","JPN":"えっと……その。","ENG":"Err... So...","TWN":"嗯……是這樣的。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"전 동료분들과 함께 여기로 왔다가 길을 잃어버렸어요.","JPN":"私は仲間と一緒に来ましたけど、はぐれて道に迷ったのです。","ENG":"I came here with my colleagues, but I think I'm lost.","TWN":"我和幾個同伴來到這裡，結果迷路了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"혹시 여기서 어떻게 나가는지 알고 있나요? 동료들을 다시 만나야 하거든요.","JPN":"ここから出る方法を知っていますか？　仲間と会わなければいけないんですよ。","ENG":"Do you know how to get out of here? I really need to find them.","TWN":"你知道如何離開這裡嗎？我得趕快去找我的同伴。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"어… 꼭 나가야 해?","JPN":"え……どうしても出なければいけないの？","ENG":"Uh... Do you really have to go?","TWN":"呃……一定要離開嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_SERIOUS2"}}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Sorry?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_SERIOUS2"}}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"나랑 같이 있자. 나 여기 엄청 오랫동안 혼자만 있었거든.","JPN":"私と一緒にいようよ。私、長い間ここで一人だったんだ。","ENG":"Stay here with me. I've been here alone for a very long time.","TWN":"來陪我吧。我一個人在這裡已經很久了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으, 으… 저랑 똑같이 생긴 사람이 저런 표정으로 부탁해버리면…","JPN":"う、うぅ……私と同じ顔の人にあんな表情でお願いされると……","ENG":"Um... I don't know what to say when a person who looks exactly like me asks with that expression...","TWN":"唉，唉……和我長得一模一樣的人以那種表情拜託我……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"잠깐… 정도는 놀아줄 수도 있긴 하지만요. 바빠서 오래는 못 있어요?","JPN":"ちょっと……くらいなら遊べますけど、忙しいからそう長くは居られませんよ？","ENG":"Maybe... I can play with you for a little while. But I can't stay long, okay?","TWN":"我……我可以陪你玩一下下。但我很忙，不能待太久喔？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"헤헤, 고마워.","JPN":"へへ、ありがとう。","ENG":"He he, thanks.","TWN":"嘿嘿，謝謝。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"그럼 이것 좀 볼래?","JPN":"じゃあ、これ見てみない？","ENG":"Then will you take a look at this?","TWN":"那看看這個吧？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오, 바닥에 나뭇가지로 그림 그리기네요!","JPN":"お、木の枝で地面に絵を描いたんですね！","ENG":"Oh, you're drawing on the ground with a stick!","TWN":"喔，用木頭在地板上畫畫！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저도 어릴 때 이런 거 자주 했어요!","JPN":"私も子供の頃よくやっていました！","ENG":"I used to do that a lot when I was a kid!","TWN":"我小時候經常這樣玩！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"정말? 그럼 이게 뭔지 알아 맞출 수 있어?","JPN":"本当？　じゃあ、これが何かわかる？","ENG":"Really? Then can you guess what I'm drawing?","TWN":"真的嗎，那你能猜到這是什麼嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으음…!","JPN":"ううむ……！","ENG":"Um...!","TWN":"唔……！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이건 손잡고 있는 커플, 이건 사과 나무, 그리고 이건 커다란 강아지네요!","JPN":"これは手を繋いでいるカップル、これはリンゴの木、そしてこれは大きいワンちゃんですね！","ENG":"This one's a couple holding hands, this is an apple tree, and the last one is a big puppy!","TWN":"這是一對牽手的情侶，這是一棵蘋果樹，這是一隻大狗！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"와아, 신기하다. 엄청 못 그렸다고 생각했는데, 이걸 맞히다니.","JPN":"わあ、不思議。凄く下手だと思ったのに、これがわかるなんて。","ENG":"Wow! That's amazing! I thought my drawings were horrible, but you got them all right.","TWN":"哇，太神奇了。我還以為自己畫得很糟糕，沒想到你都能猜到。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아니에요. 당신도 저만큼 잘 그리는데요?","JPN":"いいえ。あなたも私くらい上手ですよ？","ENG":"No, you're not. You draw just as well as I do.","TWN":"不，你畫得和我一樣好。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런데 이런 것들은 어디서 보고 그린 거죠? 여긴 나무나 강아지 같은 건 하나도 안 보이는데.","JPN":"でもこれはどこで見て描いたのですか？　ここには木やワンちゃんなんてまったく見当たらないのですが。","ENG":"But where have you seen these things to draw? I don't see any puppies or trees around here.","TWN":"但你是在哪裡看到這些的？ 我在這裡沒有看到任何樹木或小狗。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"꿈에서 본 거야. 난 꿈을 꿀 때마다 많은 걸 보거든.","JPN":"夢で見たの。私は夢を見るたびに色んなものをたくさん見るからね。","ENG":"I saw them in my dreams. I see a lot of things when I dream.","TWN":"我在夢裡看到的，我在夢裡會看到很多東西。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"이건 그 중에서도 내 기억에 남는 가장 갖고 싶은 것들을 그린 거고.","JPN":"これはその中でも私の記憶に残っている一番欲しいものを描いたの。","ENG":"I drew the things that are most memorable and desirable to me.","TWN":"而這些是我最想保留的記憶。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"아, 그리고 얜 그냥 큰 강아지가 아니라, 골든 리트리버라는 견종이야.","JPN":"あ、そしてこの子はただ大きいワンちゃんではなく、ゴールデン・レトリバーという犬種だよ。","ENG":"Oh, and that's not just a big puppy, it's a golden retriever.","TWN":"喔，牠不是普通的大狗，是一隻黃金獵犬。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그거 우연이네요. 저희 집에서 키우는 개도…","JPN":"それは偶然ですね。私の家で飼っている犬も……","ENG":"What a coincidence. The dog I have at home is also...","TWN":"真巧，我們家養的狗也是……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"이름은 치즈.","JPN":"名前はチーズ。","ENG":"His name is Cheese.","TWN":"名字叫起司。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"색깔이랑 어울리지? 아빠엄마의 농장을 지켜주는 충성스러운 친구야.","JPN":"毛の色にぴったりでしょ？　お父さんとお母さんの農場を守ってくれる忠誠心が強い友達だよ。","ENG":"Doesn't his name go well with his fur? He's a loyal dog that protects my parents' farm.","TWN":"很適合牠吧？牠會幫爸爸媽媽保護農場，是對我很忠誠的朋友。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네…?","JPN":"えっ……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"당신한테 정말 그런 이름의 개가 있다고요?","JPN":"あなたに本当にそんな名前の犬がいるんですか？","ENG":"Do you really have a dog with that name?","TWN":"你真養了一隻叫起司的狗？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"노, 놀리는 거 아니지? 말했잖아. 이건 내가 정말 있는 게 아니라, 갖고 싶은 거라구.","JPN":"か、からかっているの？　言ったでしょう。これは本当にあるものではなくて、私が欲しいものだって。","ENG":"Y-you're not teasing me, right? I told you. These are not things that I really have, but things I want.","TWN":"你、你沒騙我吧？我說過，這是我想要的，而不是已經擁有的。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"치즈도… 엄마 아빠도… 이런 넓은 과일숲도…","JPN":"チーズも……お母さんも、お父さんも……こんな広い果樹園も……","ENG":"Cheese... Mom and Dad... and even the vast orchard...","TWN":"起司……爸爸媽媽……還有這個大果林……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"나한텐… 아무것도 없단 말이야.","JPN":"私には……何もないんだ。","ENG":"You see... I have none of those.","TWN":"我……什麼都沒有。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"당신… 정체가 뭐죠?","JPN":"あなた……何者ですか？","ENG":"Who... are you?","TWN":"你……你是誰？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"노엘 라이트…….","JPN":"ノエル・ライト……","ENG":"Noelle Wright...","TWN":"洛艾兒·萊特……"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마침내 당신을 이곳 파노라마의 세계에 초청할 수 있었군요.","JPN":"ついにあなたをここ、パノラマの世界に招待することに成功しましたね。","ENG":"I was finally able to invite you into Panorama's world.","TWN":"終於能邀請你來到這個全景世界了。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 거울 세계에 발을 들인 자는 예외 없이 자신과 똑같은 거울상과 충돌하게 됩니다.","JPN":"この鏡の世界に足を踏み入れた者は、誰しも自分と同じ鏡像と衝突することになります。","ENG":"Anyone who steps into the mirror world will face against a mirror image of themselves without exception.","TWN":"踏入這個鏡子世界的人，無一例外都會與自己的鏡像發生衝突。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 당신은 달라요.","JPN":"ですが、あなたは違う。","ENG":"But you're different.","TWN":"但是你不一樣。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신과 마주한 저 거울상은 그저 당신의 껍데기인 허상만을 비추고 있을 뿐이죠.","JPN":"あなたと向き合ったあの鏡像は、ただあなたの殻である虚像を映しているだけ。","ENG":"The reflection you face is nothing but a mere shell, an illusion.","TWN":"與你面對的那面鏡子，只不過映出了你外殼的虛像而已。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"다시 말해, 이 파노라마의 세계조차 당신의 본질을 제대로 비출 수 없다는 뜻.","JPN":"つまり、このパノラマの世界すらあなたの本質を明確に映せないということ。","ENG":"In other words, not even Panorama's world is able to properly reflect your essence.","TWN":"換句話說，即使是這個全景世界也無法真正反映你的本質。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 모든 것은 각본대로.","JPN":"ですが、すべては脚本どおりに。","ENG":"But everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"거울의 맺힌 상이 흐릿할수록, 당신은 스스로의 존재를 의심할 수밖에 없을 겁니다.","JPN":"鏡に映った像がぼやけているほど、あなたは自分の存在を疑うことになるでしょう。","ENG":"As your reflection gets blurrier, you will have no choice but to doubt your existence.","TWN":"鏡中的影像越模糊，你就越會懷疑自己的存在。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 의심이야 말로 비로소 진실을 자각하는 첫 걸음.","JPN":"そして疑心こそが真実を自覚する第一歩。","ENG":"And that doubt will be the first step to realizing the truth.","TWN":"而懷疑正是覺察真相的第一步。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이야기가 종극에 다다랐을 때, 당신은 스스로의 진실을 받아들일 수 있을까요?","JPN":"物語が最後を迎えようとする時、あなたは自分の真実を受け入れられるのでしょうか？","ENG":"When the story reaches its end, will you be able to accept your own truth?","TWN":"當故事走到盡頭時，你能接受關於自己的真相嗎？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};